import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface CardRendererProps {
  block: Block;
  theme: Theme;
  onEditIcon?: (block: Block) => void;
}

export function CardRenderer({ block, theme, onEditIcon }: CardRendererProps) {
  const customIcon = block.options?.customIcon;
  const iconName = block.options?.icon;

  const text = Array.isArray(block.content) ? block.content.join(' ') : (block.content || '') as string;
  const highlight = block.options?.highlight;
  const variant = block.options?.variant || 'default';
  const hasBgHighlight = text.includes('[[');

  const isFeature = variant === 'accent' || variant === 'box';
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;

  const containerStyles: React.CSSProperties = {
    backgroundColor: isFeature ? (theme.colors.cardBg || theme.colors.accent) : 'rgba(255,255,255,0.06)',
    opacity: isFeature ? opacity : 1,
    borderColor: isFeature ? 'transparent' : 'rgba(255,255,255,0.1)',
    borderWidth: '2px',
    color: isFeature ? '#000000' : theme.colors.textPrimary,
    borderRadius: '40px',
    textWrap: 'balance' as any
  };

  const renderRichContent = () => {
    let parts: (string | React.ReactNode)[] = [text];

    // Handle Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-3 py-1 rounded-lg mx-1 font-black"
                  style={{ 
                    backgroundColor: isFeature ? '#fff' : theme.colors.accent,
                    color: '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Highlight
    if (highlight && typeof highlight === 'string' && highlight.trim() !== '') {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(<span key={`hl-${i}`} className="font-black" style={{ color: isFeature ? '#000' : theme.colors.highlight, fontWeight: 900 }}>{s}</span>);
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Markdown Bold
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>);
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  const renderIcon = () => {
    if (customIcon) {
       if (customIcon.startsWith('<svg')) {
          return (
            <div 
              className="w-12 h-12 flex items-center justify-center"
              dangerouslySetInnerHTML={{ __html: customIcon }} 
              style={{ color: isFeature ? '#000' : theme.colors.accent }}
            />
          );
       }
       if (customIcon.startsWith('http')) {
          return <img src={customIcon} className="w-12 h-12 object-contain" alt="icon" />;
       }
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={48} strokeWidth={2} />;
    }

    const targetIconName = iconName || (variant === 'accent' ? 'Zap' : 'CircleDot');
    const IconComponent = (Icons as any)[targetIconName];

    if (IconComponent) {
      return <IconComponent size={48} strokeWidth={2} />;
    }

    return null;
  };

  return (
    <div 
      className="relative flex items-center gap-8 p-10 w-full transition-all shadow-lg hover:translate-y-[-4px]" 
      style={containerStyles}
    >
      <div 
        onClick={() => onEditIcon?.(block)}
        className="group relative cursor-pointer shrink-0"
      >
        <div className="opacity-80 group-hover:opacity-100 transition-opacity" style={{ color: isFeature ? '#000' : theme.colors.accent }}>
          {renderIcon()}
        </div>
        <div className="absolute inset-[-10px] bg-emerald-500/20 border-2 border-emerald-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
           <Icons.Edit3 size={20} className="text-emerald-500" />
