      </div>

      <div className={`flex-1 text-[32px] ${hasBgHighlight ? '!leading-[1.7]' : '!leading-[1.3]'} tracking-tight`} style={{ fontWeight: 300 }}>
        {renderRichContent()}
      </div>
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface BoxRendererProps {
  block: Block;
  theme: Theme;
  isGridMember?: boolean;
  indexInGrid?: number;
  onEditIcon?: (block: Block) => void;
}

export function BoxRenderer({ block, theme, isGridMember, indexInGrid = 0, onEditIcon }: BoxRendererProps) {
  const text = (block.content || '') as string;
  const iconName = block.options?.icon;
  const variant = block.options?.variant || 'default';
  const align = block.options?.align || (isGridMember ? 'center' : 'left');
  const hasBgHighlight = text.includes('[[');

  const IconComponent = iconName ? (Icons as any)[iconName] : null;

  const renderRichText = (input: string) => {
    let parts: (string | React.ReactNode)[] = [input];

    // Handle Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-4 py-1 rounded-xl mx-1 font-black"
                  style={{ 
                    backgroundColor: '#fff',
                    color: '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Markdown Bold **
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>);
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  const isOutlined = variant === 'outlined';
  const shouldReverseIcon = !isGridMember && indexInGrid % 2 === 1;
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;

  return (
    <div 
      className={`relative w-full p-12 rounded-[60px] flex flex-col transition-all overflow-hidden ${isGridMember ? 'min-h-[220px] justify-center' : 'min-h-[180px] justify-center'} ${isOutlined ? 'border-[4px]' : ''}`}
      style={{ 
        backgroundColor: isOutlined ? 'transparent' : (theme.colors.cardBg || theme.colors.accent),
        opacity: isOutlined ? 1 : opacity,
        borderColor: theme.colors.accent,
        color: isOutlined ? theme.colors.textPrimary : '#000000',
        textAlign: align === 'center' ? 'center' : 'left'
      }}
    >
      <div className={`flex items-center gap-6 ${align === 'center' ? 'flex-col' : (shouldReverseIcon ? 'flex-row-reverse' : 'flex-row')}`}>
        {IconComponent && (
          <div 
            onClick={() => onEditIcon?.(block)}
            className="group relative cursor-pointer shrink-0"
          >
            <div className="opacity-100 group-hover:opacity-70 transition-opacity">
              <IconComponent size={isGridMember ? 80 : 120} strokeWidth={1.5} />
            </div>
            <div className="absolute inset-[-15px] bg-emerald-500/20 border-2 border-emerald-500 rounded-3xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
               <Icons.Edit3 size={32} className="text-emerald-500" />
            </div>
          </div>
        )}
        <div className={`flex-1 text-[34px] ${hasBgHighlight ? '!leading-[1.5]' : '!leading-[1.2]'} tracking-tight font-medium ${align === 'center' ? 'mt-4' : ''}`}>
          {renderRichText(text)}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface CardRendererProps {
  block: Block;
  theme: Theme;
  onEditIcon?: (block: Block) => void;
}

export function CardRenderer({ block, theme, onEditIcon }: CardRendererProps) {
  const customIcon = block.options?.customIcon;
  const iconName = block.options?.icon;

  const text = Array.isArray(block.content) ? block.content.join(' ') : (block.content || '') as string;
  const highlight = block.options?.highlight;
  const variant = block.options?.variant || 'default';
  const hasBgHighlight = text.includes('[[');

  // Modificado: Agora 'default' também segue a cor de cardBg do tema para maior consistência
  // Apenas 'ghost' e 'outlined' (se existirem no futuro) seriam exceções
  const isFeature = variant === 'default' || variant === 'accent' || variant === 'box';
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;

  const containerStyles: React.CSSProperties = {
    backgroundColor: isFeature ? (theme.colors.cardBg || theme.colors.accent) : 'rgba(255,255,255,0.06)',
    // Aplicar opacidade apenas se for um card com cor sólida
    opacity: isFeature ? opacity : 1,
    borderColor: isFeature ? 'transparent' : 'rgba(255,255,255,0.1)',
    borderWidth: '2px',
    // Texto preto para fundo de destaque (como o amarelo do exemplo), branco para o padrão translúcido
    color: isFeature ? '#000000' : theme.colors.textPrimary,
    borderRadius: '40px',
    textWrap: 'balance' as any
  };

  const renderRichContent = () => {
    let parts: (string | React.ReactNode)[] = [text];

    // Handle Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-3 py-1 rounded-lg mx-1 font-black"
                  style={{ 
                    backgroundColor: isFeature ? '#fff' : theme.colors.accent,
                    color: '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Highlight
    if (highlight && typeof highlight === 'string' && highlight.trim() !== '') {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(<span key={`hl-${i}`} className="font-black" style={{ color: isFeature ? '#000' : theme.colors.highlight, fontWeight: 900 }}>{s}</span>);
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Markdown Bold
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>);
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  const renderIcon = () => {
    if (customIcon) {
       if (customIcon.startsWith('<svg')) {
          return (
            <div 
              className="w-12 h-12 flex items-center justify-center"
              dangerouslySetInnerHTML={{ __html: customIcon }} 
              style={{ color: isFeature ? '#000' : theme.colors.accent }}
            />
          );
       }
       if (customIcon.startsWith('http')) {
          return <img src={customIcon} className="w-12 h-12 object-contain" alt="icon" />;
       }
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={48} strokeWidth={2} />;
    }

    const targetIconName = iconName || (variant === 'accent' || variant === 'default' ? 'Zap' : 'CircleDot');
    const IconComponent = (Icons as any)[targetIconName];

    if (IconComponent) {
      return <IconComponent size={48} strokeWidth={2} />;
    }

    return null;
  };

  return (
    <div 
      className="relative flex items-center gap-8 p-10 w-full transition-all shadow-lg hover:translate-y-[-4px]" 
      style={containerStyles}
    >
      <div 
        onClick={() => onEditIcon?.(block)}
        className="group relative cursor-pointer shrink-0"
      >
        <div className="opacity-80 group-hover:opacity-100 transition-opacity" style={{ color: isFeature ? '#000' : theme.colors.accent }}>
          {renderIcon()}
        </div>
        <div className="absolute inset-[-10px] bg-emerald-500/20 border-2 border-emerald-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
           <Icons.Edit3 size={20} className="text-emerald-500" />
        </div>
      </div>

      <div className={`flex-1 text-[32px] ${hasBgHighlight ? '!leading-[1.7]' : '!leading-[1.3]'} tracking-tight`} style={{ fontWeight: 300 }}>
        {renderRichContent()}
      </div>
    </div>
  );
}

