                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Highlight (options.highlight)
    {
      const highlightTerm = highlight;
      if (highlightTerm) {
        const newParts: (string | React.ReactNode)[] = [];
        parts.forEach(part => {
          if (typeof part === 'string') {
            const split = part.split(new RegExp(`(${highlightTerm})`, 'gi'));
