                              <Library size={20} className={currentSlide?.template === tpl.name ? 'text-black' : 'text-zinc-500'} />
                           </div>
                           <div>
                              <p className={`text-[10px] font-black uppercase mb-0.5 tracking-tighter ${currentSlide?.template === tpl.name ? 'text-emerald-400' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p>
                              <p className="text-[9px] text-zinc-500 opacity-60 font-medium">{tpl.description}</p>
                           </div>
                        </div>
                        {currentSlide?.template === tpl.name && <Check className="text-emerald-500" size={16} />}
                      </button>
                    ))}
                </div>
              ) : activeTab === 'TEXTURES' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                   <section className="space-y-4">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Layers size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Tipo de Ruído</h3></div>
                      <div className="grid grid-cols-2 gap-2">
                        {TEXTURE_PRESETS.map(preset => (
                          <button key={preset.id} onClick={() => updateSlideProperty(['options', 'texture', 'type'], preset.id)} className={`flex flex-col items-center gap-2 p-4 rounded-2xl border transition-all ${currentSlide?.options?.texture?.type === preset.id ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-zinc-300'}`}><preset.icon size={20} /><span className="text-[9px] font-black uppercase tracking-widest">{preset.label}</span></button>
                        ))}
                      </div>
                   </section>
                   <section className="space-y-6">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Wind size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Ajustes de Textura</h3></div>
                      <div className="space-y-8">
                        <TransformControl label="Intensidade (Opacidade)" value={currentSlide?.options?.texture?.amount ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateSlideProperty(['options', 'texture', 'amount'], v)} />
                        <div className="space-y-2.5">
                           <span className="text-[9px] font-black text-zinc-500 uppercase px-1 tracking-widest">Modo de Camada (Blend)</span>
                           <div className="grid grid-cols-2 gap-1.5 max-h-[200px] overflow-y-auto custom-scrollbar pr-1">{BLEND_MODES.map(mode => (<button key={mode} onClick={() => updateSlideProperty(['options', 'texture', 'blendMode'], mode)} className={`py-2 px-3 rounded-lg text-left text-[9px] font-black uppercase tracking-tighter border transition-all ${currentSlide?.options?.texture?.blendMode === mode ? 'bg-emerald-500 text-black border-emerald-500' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`}>{mode}</button>))}</div>
                        </div>
                      </div>
                   </section>
                </div>
              ) : activeTab === 'ASSETS' ? (
                <div className="space-y-8 animate-in fade-in duration-300">
                  <div className={`p-6 border rounded-[32px] transition-all ${isLocked ? 'opacity-50 pointer-events-none' : 'bg-white/5 border-white/10'}`}>
                    {imageConfig?.url ? (
                      <div className="space-y-10">
                        <div className="relative aspect-video rounded-2xl overflow-hidden bg-zinc-950 border border-white/5 group shadow-inner">
                          <img src={imageConfig.url} className="w-full h-full object-contain" />
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                              <button onClick={() => updateSlideProperty(['image', 'url'], undefined)} className="p-3 bg-red-500 text-white rounded-xl shadow-xl hover:scale-110 transition-transform"><Trash2 size={20}/></button>
                          </div>
                        </div>

                        {/* Layout Selector */}
                        <div className="space-y-4">
                           <span className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Layout de Imagem</span>
                           <div className="grid grid-cols-5 gap-2">
                              {IMAGE_TYPE_PRESETS.map(preset => (
                                <button 
                                  key={preset.id} 
                                  onClick={() => updateSlideProperty(['image', 'type'], preset.id)}
                                  className={`flex flex-col items-center gap-2 p-2 rounded-xl border transition-all ${imageConfig.type === preset.id ? 'bg-emerald-500 border-emerald-500 text-black shadow-lg' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`}
                                  title={preset.label}
                                >
                                  <preset.icon size={16} />
                                </button>
                              ))}
                           </div>
                        </div>

                        {/* Controles de Posição e Lado */}
                        {(imageConfig.type === 'IMAGE_BOX' || imageConfig.type === 'FOCUS_SUBJECT' || imageConfig.type === 'IMAGE_SPLIT_HALF') && (
                           <div className="space-y-4">
                              <span className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Posição e Orientação</span>
                              <div className="flex gap-2">
                                 {/* Toggle Lado (Esquerda/Direita) */}
                                 <button 
                                    onClick={() => updateSlideProperty(['image', 'position'], imageConfig.position === 'left' ? 'right' : 'left')}
                                    className="flex-1 py-4 bg-zinc-800 rounded-2xl border border-white/5 flex flex-col items-center gap-2 hover:bg-zinc-700 transition-all group"
                                 >
                                    <div className="flex items-center gap-3">
                                       <AlignLeft size={16} className={imageConfig.position === 'left' ? 'text-emerald-400' : 'text-zinc-600'} />
                                       <div className="w-4 h-2 bg-zinc-600 rounded-full relative overflow-hidden">
                                          <div className={`absolute inset-y-0 w-1/2 bg-emerald-500 transition-all ${imageConfig.position === 'left' ? 'left-0' : 'left-1/2'}`} />
                                       </div>
                                       <AlignRight size={16} className={imageConfig.position === 'right' ? 'text-emerald-400' : 'text-zinc-600'} />
                                    </div>
                                    <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-500 group-hover:text-zinc-300">Posição Lateral</span>
                                 </button>

                                 {/* Toggle Vertical (Apenas Split) */}
                                 {imageConfig.type === 'IMAGE_SPLIT_HALF' && (
                                    <button 
                                       onClick={() => updateSlideProperty(['image', 'position'], (imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'right' : 'top')}
                                       className="flex-1 py-4 bg-zinc-800 rounded-2xl border border-white/5 flex flex-col items-center gap-2 hover:bg-zinc-700 transition-all group"
                                    >
                                       <div className="flex items-center gap-3">
                                          <MoveVertical size={16} className={(imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'text-emerald-400' : 'text-zinc-600'} />
                                          <div className="w-4 h-2 bg-zinc-600 rounded-full relative overflow-hidden">
                                             <div className={`absolute inset-y-0 w-1/2 bg-emerald-500 transition-all ${(imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'left-1/2' : 'left-0'}`} />
                                          </div>
                                          <MoveHorizontal size={16} className={(imageConfig.position === 'left' || imageConfig.position === 'right') ? 'text-emerald-400' : 'text-zinc-600'} />
                                       </div>
                                       <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-500 group-hover:text-zinc-300">Eixo V / H</span>
                                    </button>
                                 )}
                              </div>
                           </div>
                        )}

                        <div className="space-y-6">
                          <div className="flex gap-4">
                            <TransformControl label="Escala" value={imageConfig.scale ?? 1} min={0.1} max={5} step={0.05} onChange={(v) => updateSlideProperty(['image', 'scale'], v)} />
                            {imageConfig.type === 'IMAGE_BOX' && <TransformControl label="Largura Box" value={imageConfig.width ?? 480} min={200} max={1000} step={10} onChange={(v) => updateSlideProperty(['image', 'width'], v)} />}
                          </div>

                          <div className="flex gap-4">
                             <TransformControl label="Offset X" value={imageConfig.x ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'x'], v)} />
                             <TransformControl label="Offset Y" value={imageConfig.y ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'y'], v)} />
                          </div>

                          <TransformControl label="Opacidade do Fundo" value={imageConfig.backgroundOpacity ?? 1} min={0} max={1} step={0.05} onChange={(v) => updateSlideProperty(['image', 'backgroundOpacity'], v)} />
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-white/5 rounded-[40px] hover:bg-white/5 transition-all relative group cursor-pointer">
                        <PlusCircle className="w-10 h-10 text-zinc-800 mb-4 group-hover:text-emerald-500 transition-colors" /><p className="text-[10px] font-black uppercase text-zinc-600 group-hover:text-zinc-400">Arraste ou clique para Upload</p><input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleImageUpload} disabled={isLocked} />
                      </div>
                    )}
                  </div>
                  <div className="px-1 py-4 bg-zinc-800/20 border border-zinc-700/30 rounded-2xl flex flex-col items-center gap-3"><ClipboardPaste size={20} className="text-zinc-600" /><p className="text-[10px] font-black uppercase text-zinc-500 text-center px-4">Use CTRL+V no editor para colar imagens rapidamente!</p></div>
                </div>
              ) : activeTab === 'JSON' ? (
                <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[500px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none" spellCheck={false} />
              ) : null}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950 flex gap-3">
              <button disabled={!carousel || isExporting} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="flex-1 py-4 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black rounded-xl text-[10px] uppercase transition-all shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar</button>
            </footer>
          </aside>

          {/* CANVAS AREA */}
          <main className="flex-1 bg-[#18181b] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4 duration-300"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
            <div className="absolute top-5 right-5 z-40 flex items-center gap-0.5 bg-black/30 backdrop-blur-xl p-1 rounded-xl border border-white/5 opacity-60 hover:opacity-100 transition-opacity">
              <button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={16} /></button>
              <div className="px-2 text-[9px] font-black font-mono text-zinc-400 w-10 text-center">{(zoom * 100).toFixed(0)}%</div>
              <button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={16} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}>
              <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">
                {carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(block, blockIdx) => setEditingIconBlock({ block, index: blockIdx })} /> : <div className="opacity-10"><Loader2 className="w-10 h-10 animate-spin text-emerald-500" /></div>}
              </div>
            </div>
            {carousel && carousel.slides.length > 0 && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl transition-opacity hover:opacity-100 opacity-90">
                 <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20} strokeWidth={3}/></button>
                 <div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-emerald-500 shadow-lg shadow-emerald-500/30' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div>
                 <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20} strokeWidth={3}/></button>
              </div>
            )}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Block, Theme } from '../../types';
import * as Icons from 'lucide-react';

interface CardRendererProps {
  block: Block;
  theme: Theme;
  onEditIcon?: (block: Block) => void;
}

export function CardRenderer({ block, theme, onEditIcon }: CardRendererProps) {
  const customIcon = block.options?.customIcon;
  const iconName = block.options?.icon;

  const text = Array.isArray(block.content) ? block.content.join(' ') : (block.content || '') as string;
  const highlight = block.options?.highlight;
  const variant = block.options?.variant || 'default';
  const hasBgHighlight = text.includes('[[');

  // Determinamos se o card deve usar a cor de destaque da marca
  const isAccent = variant === 'accent' || variant === 'box' || variant === 'default';
  const opacity = theme.colors.cardOpacity !== undefined ? theme.colors.cardOpacity : 1;
  const cardColor = theme.colors.cardBg || theme.colors.accent;

  const containerStyles: React.CSSProperties = {
    backgroundColor: isAccent ? cardColor : 'rgba(255,255,255,0.06)',
    opacity: isAccent ? opacity : 1,
    borderColor: isAccent ? 'transparent' : 'rgba(255,255,255,0.1)',
    borderWidth: '2px',
    color: isAccent ? '#000000' : theme.colors.textPrimary,
    borderRadius: '40px',
    textWrap: 'balance' as any
  };

  const renderRichContent = () => {
    let parts: (string | React.ReactNode)[] = [text];

    // Handle Background Accent Highlight [[...]]
    {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(/\[\[(.*?)\]\]/g);
          split.forEach((s, i) => {
            if (i % 2 === 1) {
              newParts.push(
                <span 
                  key={`bg-hl-${i}`} 
                  className="inline px-3 py-1 rounded-lg mx-1 font-black"
                  style={{ 
                    backgroundColor: isAccent ? '#fff' : theme.colors.accent,
                    color: '#000',
                    WebkitBoxDecorationBreak: 'clone',
                    boxDecorationBreak: 'clone' as any,
                  }}
                >
                  {s}
                </span>
              );
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Highlight
    if (highlight && typeof highlight === 'string' && highlight.trim() !== '') {
      const newParts: (string | React.ReactNode)[] = [];
      parts.forEach(part => {
        if (typeof part === 'string') {
          const split = part.split(new RegExp(`(${highlight})`, 'gi'));
          split.forEach((s, i) => {
            if (s.toLowerCase() === highlight.toLowerCase()) {
              newParts.push(<span key={`hl-${i}`} className="font-black" style={{ color: isAccent ? '#000' : theme.colors.highlight, fontWeight: 900 }}>{s}</span>);
            } else if (s !== "") {
              newParts.push(s);
            }
          });
        } else {
          newParts.push(part);
        }
      });
      parts = newParts;
    }

    // Handle Markdown Bold
    const finalParts: (string | React.ReactNode)[] = [];
    parts.forEach(part => {
      if (typeof part === 'string') {
        const split = part.split(/\*\*(.*?)\*\*/g);
        split.forEach((s, i) => {
          if (i % 2 === 1) {
            finalParts.push(<span key={`bold-${i}`} className="font-black" style={{ fontWeight: 900 }}>{s}</span>);
          } else if (s !== "") {
            finalParts.push(s);
          }
        });
      } else {
        finalParts.push(part);
      }
    });

    return finalParts;
  };

  const renderIcon = () => {
    if (customIcon) {
       if (customIcon.startsWith('<svg')) {
          return (
            <div 
              className="w-12 h-12 flex items-center justify-center"
              dangerouslySetInnerHTML={{ __html: customIcon }} 
              style={{ color: isAccent ? '#000' : theme.colors.accent }}
            />
          );
       }
       if (customIcon.startsWith('http')) {
          return <img src={customIcon} className="w-12 h-12 object-contain" alt="icon" />;
       }
       const IconFromCustom = (Icons as any)[customIcon];
       if (IconFromCustom) return <IconFromCustom size={48} strokeWidth={2} />;
    }

    const targetIconName = iconName || (variant === 'accent' || variant === 'default' ? 'Zap' : 'CircleDot');
    const IconComponent = (Icons as any)[targetIconName];

    if (IconComponent) {
      return <IconComponent size={48} strokeWidth={2} />;
    }

    return null;
  };

  return (
    <div 
      className="relative flex items-center gap-8 p-10 w-full transition-all shadow-lg hover:translate-y-[-4px]" 
      style={containerStyles}
    >
      <div 
        onClick={() => onEditIcon?.(block)}
        className="group relative cursor-pointer shrink-0"
      >
        <div className="opacity-80 group-hover:opacity-100 transition-opacity" style={{ color: isAccent ? '#000' : theme.colors.accent }}>
          {renderIcon()}
        </div>
        <div className="absolute inset-[-10px] bg-emerald-500/20 border-2 border-emerald-500 rounded-xl opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center scale-90 group-hover:scale-100">
           <Icons.Edit3 size={20} className="text-emerald-500" />
        </div>
      </div>

      <div className={`flex-1 text-[32px] ${hasBgHighlight ? '!leading-[1.7]' : '!leading-[1.3]'} tracking-tight`} style={{ fontWeight: 300 }}>
        {renderRichContent()}
      </div>
    </div>
  );
}
